function renderReport({
  marker,
  mode,
  ledgerRef,
  repoFullName,
  prNumber,
  generatedAt,
  base,
  head,
  commits,
  sessions,
  changedFiles = [],
  testFiles = [],
  qaDigest = null,
  missingLedgerRef = false,
  artifact = null,
}) {
  const title = mode === 'final'
    ? 'OpenSession Review (final snapshot)'
