    if (manifestLink) {
      lines.push(`- Artifact manifest: [manifest.json](${manifestLink})`);
    }
  }
  if (artifact?.enabled && artifact?.error) {
    lines.push(`- Artifact publish: failed (\`${artifact.error}\`)`);
  }
  if (missingLedgerRef) {
