function pushDetailsList(lines, summary, items, formatter, limit = 12) {
  if (!items.length) return;
  lines.push('<details>');
  lines.push(`<summary>${summary}</summary>`);
  lines.push('');
  for (const item of items.slice(0, limit)) {
    lines.push(`- ${formatter(item)}`);
